#include<bits/stdc++.h>
using namespace std;
vector<long long> mp[200010];
long long n,s[200010],k[200010],f[200010],ans[200010],r[200010];
bool vis[200010];
int main()
{
    scanf("%lld",&n);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld%lld%lld",&s[i],&k[i],&r[i]);
        for(long long j=1;j<=r[i];j++)
        {
            long long x;
            scanf("%lld",&x);
            mp[x].push_back(i);
        }
    }
    priority_queue<pair<long long,long long>> q;
    for(long long i=1;i<=n;i++)
    {
        q.push(make_pair(-k[i],i));
        f[i]=s[i];
    }
    while(!q.empty())
    {
        long long t=q.top().second,w=(-q.top().first);
        q.pop();
        if(vis[t])
        {
            continue;
        }
        vis[t]=1;
        ans[t]=w;
        for(long long i:mp[t])
        {
            if(!vis[i]&&f[i]<=k[i])
            {
                f[i]+=w;
                r[i]--;
                if(r[i]==0)
                {
                    q.push(make_pair(-f[i],i));
                }
            }
        }
    }
    printf("%lld",ans[1]);
    return 0;
}
